firmware_template.source:
#include "solenoid.h"
#include <Arduino.h>
#define SOL_PIN 25
static bool _on=false;
void solenoid_setup(){pinMode(SOL_PIN,OUTPUT);digitalWrite(SOL_PIN,LOW);Serial.println("[solenoid] OK");}
void solenoid_on(){digitalWrite(SOL_PIN,HIGH);_on=true;}
void solenoid_off(){digitalWrite(SOL_PIN,LOW);_on=false;}
void solenoid_pulse(uint16_t ms){solenoid_on();delay(ms);solenoid_off();}
bool solenoid_state(){return _on;}
